+func rollbackLandAfterFailure(projectRoot, wd string, req LandRequest, gitOps LandingGitOps, targetRef, preLandTip, landedTip string, dirtyBefore []string, cause error) error {
+	preserveRef := landIterationRef(req.BeadID, req.AttemptID, preLandTip)
+	if landedTip != "" {
+		if revertErr := gitOps.UpdateRefTo(wd, targetRef, preLandTip, landedTip); revertErr != nil {
+			return fmt.Errorf("restoring %s to %s after land failure failed (preserve %s): %w", targetRef, preLandTip, preserveRef, revertErr)
+		}
+	}
+	if sameFilesystemPath(projectRoot, wd) {
+		if syncErr := syncWorkTreeToHeadExcludingPaths(wd, landedTip, dirtyBefore); syncErr != nil {
+			return fmt.Errorf("restoring project root after land failure failed (preserve %s): %w", preserveRef, syncErr)
+		}
+		if dirtyErr := assertPostLandWorktreeCleanliness(wd, landedTip, dirtyBefore); dirtyErr != nil {
+			return fmt.Errorf("post-land cleanliness assertion failed after preserving %s: %w", preserveRef, dirtyErr)
+		}
+	}
+	return fmt.Errorf("post-land cleanup failed after preserving %s: %w", preserveRef, cause)
+}
+
+func assertPostLandWorktreeCleanliness(dir, fromRev string, dirtyBefore []string) error {
+	currentDirty := dirtyWorktreePaths(dir)
+	if len(currentDirty) == 0 {
+		return nil
+	}
+	baseline := make(map[string]bool, len(dirtyBefore))
+	for _, path := range dirtyBefore {
+		baseline[filepath.ToSlash(path)] = true
+	}
+	var unexpected []string
+	for _, path := range currentDirty {
+		if baseline[filepath.ToSlash(path)] {
+			continue
+		}
+		unexpected = append(unexpected, filepath.ToSlash(path))
+	}
+	if len(unexpected) == 0 {
+		return nil
+	}
+	if overlap, err := checkoutSyncDirtyOverlapPaths(dir, fromRev, unexpected); err == nil && len(overlap) > 0 {
+		return fmt.Errorf("attempt-authored paths still dirty: %s", strings.Join(overlap, ", "))
+	}
+	return nil
+}
